-- {"operators": "FULL_OUTER_JOIN,AGGREGATE,FILTER", "complexity": "medium", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": false, "tables": "CUSTOMER,HISTORY", "ducklake": true}
SELECT COALESCE(c.C_W_ID, h.H_C_W_ID) AS w, COALESCE(c.C_ID, h.H_C_ID) AS id, COUNT(c.C_BALANCE) AS cust_rows, COUNT(h.H_AMOUNT) AS hist_rows FROM dl.CUSTOMER c FULL OUTER JOIN dl.HISTORY h ON c.C_W_ID = h.H_C_W_ID AND c.C_D_ID = h.H_C_D_ID AND c.C_ID = h.H_C_ID WHERE COALESCE(c.C_BALANCE, 0) + COALESCE(h.H_AMOUNT, 0) > 0 GROUP BY COALESCE(c.C_W_ID, h.H_C_W_ID), COALESCE(c.C_ID, h.H_C_ID);
